export function obterPerguntas(nivel: NivelQuiz, categoria?: CategoriaQuiz, quantidade: number = 10): PerguntaQuiz[] {
  let pool = nivel === 'facil' ? perguntasFacis : nivel === 'medio' ? perguntasMedias : perguntasDificeis;
  if (categoria) pool = pool.filter((p) => p.categoria === categoria);
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, Math.min(quantidade, shuffled.length));
}

export function obterPerguntasAleatorias(quantidade: number = 10): PerguntaQuiz[] {
  const shuffled = [...todasPerguntas].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, Math.min(quantidade, shuffled.length));
}

export function obterPerguntasPorLivro(livro: string, nivel?: NivelQuiz, quantidade: number = 10): PerguntaQuiz[] {
  let pool = nivel === 'facil' ? perguntasFacis : nivel === 'medio' ? perguntasMedias : nivel === 'dificil' ? perguntasDificeis : todasPerguntas;
  const filtradas = pool.filter((p) => p.referencia && p.referencia.toLowerCase().includes(livro.toLowerCase()));
  if (filtradas.length === 0) {
    const all = nivel ? pool : todasPerguntas;
    return all.sort(() => Math.random() - 0.5).slice(0, quantidade);
  }
  return filtradas.sort(() => Math.random() - 0.5).slice(0, Math.min(quantidade, filtradas.length));
}

export const todasPerguntas: PerguntaQuiz[] = [
  ...perguntasFacis,
  ...perguntasMedias,
  ...perguntasDificeis,
];